      <FilterButton text=""/>
      <div class="filter__button button-author _btn-text">исполнителю</div>
      <div class="filter__button button-year _btn-text">году выпуска</div>
      <div class="filter__button button-genre _btn-text">жанру</div>
    </div>
  );
};
